"use strict";

const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Filters problems by difficulty, tags, and limits the number of results.
 * Supports case-insensitive tag filtering with tags as comma-separated string or array.
 * Returns filtered problems and metadata including normalized tags.
 *
 * @param {Object} params
 * @param {string|Array<string>} [params.tags] - Tags to filter by (case-insensitive).
 * @param {string} [params.difficulty] - Difficulty filter.
 * @param {number} [params.limit] - Limit number of results.
 * @returns {Object} { problems: Array, metadata: Object }
 */
function getProblems(params = {}) {
  let { tags, difficulty, limit } = params;

  // Normalize tags to array of lowercase strings
  let normalizedTags = [];
  if (tags) {
    if (typeof tags === "string") {
      normalizedTags = tags.split(",").map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
    } else if (Array.isArray(tags)) {
      normalizedTags = tags.map(t => String(t).toLowerCase());
    }
  }

  // Filter problems by difficulty if provided
  let filtered = problemsData;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Filter problems by tags if provided
  if (normalizedTags.length > 0) {
    filtered = filtered.filter(p => {
      const problemTags = (p.tags || []).map(t => t.toLowerCase());
      return normalizedTags.every(tag => problemTags.includes(tag));
    });
  }

  // Sort problems by stable criteria (e.g., id ascending)
  filtered = _.sortBy(filtered, ["id"]);

  // Apply limit if provided
  if (limit && Number.isInteger(limit) && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  return {
    problems: filtered,
    metadata: {
      tags: normalizedTags
    }
  };
}

module.exports = { getProblems };
